import{_ as o,o as a,c as t,ai as l}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"grammY","description":"","frontmatter":{"read_when":["开发 Telegram 或 grammY 相关功能时"],"summary":"通过 grammY 集成 Telegram Bot API，附设置说明","title":"grammY","x-i18n":{"generated_at":"2026-02-03T10:03:55Z","model":"claude-opus-4-5","provider":"pi","source_hash":"ea7ef23e6d77801f4ef5fc56685ef4470f79f5aecab448d644a72cbab53521b7","source_path":"channels/grammy.md","workflow":15}},"headers":[],"relativePath":"zh-CN/channels/grammy.md","filePath":"zh-CN/channels/grammy.md","lastUpdated":null}'),r={name:"zh-CN/channels/grammy.md"};function c(d,e,n,m,s,g){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="grammy-集成-telegram-bot-api" tabindex="-1"><a class="header-anchor" href="#grammy-集成-telegram-bot-api">#</a> grammY 集成（Telegram Bot API）</h1><h1 id="为什么选择-grammy" tabindex="-1"><a class="header-anchor" href="#为什么选择-grammy">#</a> 为什么选择 grammY</h1><ul><li>以 TS 为核心的 Bot API 客户端，内置长轮询 + webhook 辅助工具、中间件、错误处理和速率限制器。</li><li>媒体处理辅助工具比手动编写 fetch + FormData 更简洁；支持所有 Bot API 方法。</li><li>可扩展：通过自定义 fetch 支持代理，可选的会话中间件，类型安全的上下文。</li></ul><h1 id="我们发布的内容" tabindex="-1"><a class="header-anchor" href="#我们发布的内容">#</a> 我们发布的内容</h1><ul><li><strong>单一客户端路径：</strong> 移除了基于 fetch 的实现；grammY 现在是唯一的 Telegram 客户端（发送 + Gateway 网关），默认启用 grammY throttler。</li><li><strong>Gateway 网关：</strong> <code>monitorTelegramProvider</code> 构建 grammY <code>Bot</code>，接入 mention/allowlist 网关控制，通过 <code>getFile</code>/<code>download</code> 下载媒体，并使用 <code>sendMessage/sendPhoto/sendVideo/sendAudio/sendDocument</code> 发送回复。通过 <code>webhookCallback</code> 支持长轮询或 webhook。</li><li><strong>代理：</strong> 可选的 <code>channels.telegram.proxy</code> 通过 grammY 的 <code>client.baseFetch</code> 使用 <code>undici.ProxyAgent</code>。</li><li><strong>Webhook 支持：</strong> <code>webhook-set.ts</code> 封装了 <code>setWebhook/deleteWebhook</code>；<code>webhook.ts</code> 托管回调，支持健康检查和优雅关闭。当设置了 <code>channels.telegram.webhookUrl</code> + <code>channels.telegram.webhookSecret</code> 时，Gateway 网关启用 webhook 模式（否则使用长轮询）。</li><li><strong>会话：</strong> 私聊折叠到智能体主会话（<code>agent:&lt;agentId&gt;:&lt;mainKey&gt;</code>）；群组使用 <code>agent:&lt;agentId&gt;:telegram:group:&lt;chatId&gt;</code>；回复路由回同一渠道。</li><li><strong>配置选项：</strong> <code>channels.telegram.botToken</code>、<code>channels.telegram.dmPolicy</code>、<code>channels.telegram.groups</code>（allowlist + mention 默认值）、<code>channels.telegram.allowFrom</code>、<code>channels.telegram.groupAllowFrom</code>、<code>channels.telegram.groupPolicy</code>、<code>channels.telegram.mediaMaxMb</code>、<code>channels.telegram.linkPreview</code>、<code>channels.telegram.proxy</code>、<code>channels.telegram.webhookSecret</code>、<code>channels.telegram.webhookUrl</code>。</li><li><strong>草稿流式传输：</strong> 可选的 <code>channels.telegram.streamMode</code> 在私有话题聊天中使用 <code>sendMessageDraft</code>（Bot API 9.3+）。这与渠道分块流式传输是分开的。</li><li><strong>测试：</strong> grammY mock 覆盖了私信 + 群组 mention 网关控制和出站发送；欢迎添加更多媒体/webhook 测试用例。</li></ul><p>待解决问题</p><ul><li>如果遇到 Bot API 429 错误，考虑使用可选的 grammY 插件（throttler）。</li><li>添加更多结构化媒体测试（贴纸、语音消息）。</li><li>使 webhook 监听端口可配置（目前固定为 8787，除非通过 Gateway 网关配置）。</li></ul>',7)])])}const b=o(r,[["render",c]]);export{h as __pageData,b as default};
